import{_ as s,o as a,c as n,a3 as e}from"./chunks/framework.4hqxWaF8.js";const b=JSON.parse('{"title":"AI 视频工作流全指南：从提示词到发布的自动化流水线","description":"2026年AI视频制作全流程深度教程。覆盖剧本→分镜→生成→剪辑→发布的完整工具链和自动化方案。","frontmatter":{"title":"AI 视频工作流全指南：从提示词到发布的自动化流水线","description":"2026年AI视频制作全流程深度教程。覆盖剧本→分镜→生成→剪辑→发布的完整工具链和自动化方案。","head":[["meta",{"name":"keywords","content":"AI视频,AI短剧,视频自动化,工作流,Seedance,可灵,即梦,剪映,AI批量生产"}]]},"headers":[],"relativePath":"posts/ai-video-workflow.md","filePath":"posts/ai-video-workflow.md"}'),l={name:"posts/ai-video-workflow.md"};function i(r,t,d,p,o,h){return a(),n("div",null,[...t[0]||(t[0]=[e(`<h1 style="color:#ca8a04;">AI 视频工作流全指南：从提示词到发布的自动化流水线</h1><p><em>2026年6月27日 · 阅读约 18 分钟</em></p><hr><h2 id="为什么需要工作流" tabindex="-1">为什么需要工作流？ <a class="header-anchor" href="#为什么需要工作流" aria-label="Permalink to &quot;为什么需要工作流？&quot;">​</a></h2><p>多数人用 AI 做视频的方式是：打开即梦/可灵 → 输入提示词 → 等生成 → 不满意 → 重新生成 → 还是不满意 → 凑合用。</p><p>这不是&quot;做视频&quot;，是&quot;抽卡&quot;。</p><p>真正的 AI 视频制作是一套<strong>标准化的工业管线</strong>——每个环节有确定的输入输出、有质量检查标准、有自动化脚本。你不再是一个人在抽卡，你是一个工厂的厂长。</p><hr><h2 id="完整工作流架构" tabindex="-1">完整工作流架构 <a class="header-anchor" href="#完整工作流架构" aria-label="Permalink to &quot;完整工作流架构&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes custom-dark custom-dark vp-code" tabindex="0"><code><span class="line"><span>剧本阶段          分镜阶段          生成阶段          后期阶段          发布阶段</span></span>
<span class="line"><span>┌──────────┐    ┌──────────┐    ┌──────────┐    ┌──────────┐    ┌──────────┐</span></span>
<span class="line"><span>│ 选题分析  │ → │ 画面描述  │ → │ 图生视频  │ → │ 剪辑拼接  │ → │ 多平台   │</span></span>
<span class="line"><span>│ 剧本创作  │    │ 提示词    │    │ 文生视频  │    │ 字幕配音  │    │ 分发     │</span></span>
<span class="line"><span>│ 角色设定  │    │ 风格帧    │    │ 批量生成  │    │ 调色特效  │    │ 数据分析  │</span></span>
<span class="line"><span>└──────────┘    └──────────┘    └──────────┘    └──────────┘    └──────────┘</span></span>
<span class="line"><span>   AI辅助          AI精确控制       AI生成主力       传统精修        自动化工具</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><blockquote><p><strong>核心原则</strong>：AI 管生成，人管决策。工作流的意义是把重复劳动交给机器，把创意判断留给自己。</p></blockquote><hr><h2 id="第一站-剧本阶段" tabindex="-1">第一站：剧本阶段 <a class="header-anchor" href="#第一站-剧本阶段" aria-label="Permalink to &quot;第一站：剧本阶段&quot;">​</a></h2><h3 id="选题分析" tabindex="-1">选题分析 <a class="header-anchor" href="#选题分析" aria-label="Permalink to &quot;选题分析&quot;">​</a></h3><p>先用 AI 做选题调研，而不是拍脑袋：</p><p><strong>Prompt 模板：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes custom-dark custom-dark vp-code" tabindex="0"><code><span class="line"><span>你是一个短视频运营专家。分析以下赛道最近30天的爆款内容趋势：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>赛道：[AI短剧/电商带货/文旅宣传/知识科普]</span></span>
<span class="line"><span>平台：[抖音/快手/B站/视频号]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出：</span></span>
<span class="line"><span>1. 最近爆款的5个选题方向（附播放量数据）</span></span>
<span class="line"><span>2. 每个方向的内容公式（开头/冲突/结尾结构）</span></span>
<span class="line"><span>3. 机会窗口判断（热度上升/饱和/下降）</span></span>
<span class="line"><span>4. 建议切入的具体选题</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>工具推荐</strong>：</p><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>特点</th></tr></thead><tbody><tr><td>DeepSeek / Claude</td><td>剧本创作、选题分析</td><td>中文理解最强</td></tr><tr><td>巨量算数</td><td>抖音热点趋势</td><td>官方数据</td></tr><tr><td>新榜 / 飞瓜</td><td>跨平台热点追踪</td><td>竞品分析</td></tr></tbody></table><h3 id="剧本格式标准" tabindex="-1">剧本格式标准 <a class="header-anchor" href="#剧本格式标准" aria-label="Permalink to &quot;剧本格式标准&quot;">​</a></h3><p>AI 视频剧本需要比传统剧本更精确——因为你要把它喂给下一环节的 AI。推荐使用<strong>三栏剧本格式</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes custom-dark custom-dark vp-code" tabindex="0"><code><span class="line"><span>| 时间 | 画面描述（给AI生成工具）        | 旁白/对白                      | 音效/BGM       |</span></span>
<span class="line"><span>|------|-------------------------------|------------------------------|----------------|</span></span>
<span class="line"><span>| 0-3s | 赛博朋克街道夜景，霓虹灯闪烁，    | &quot;2067年的东京...&quot;             | 电子氛围音     |</span></span>
<span class="line"><span>|      | 雨水倒映灯光，镜头缓慢推轨前进    |                              | 低频鼓点       |</span></span>
<span class="line"><span>| 3-7s | 主角特写：半张脸被霓虹照亮，      | &quot;她知道自己只剩24小时...&quot;      | 紧张弦乐渐强   |</span></span>
<span class="line"><span>|      | 另外半张隐在阴影中，眼神警觉      |                              |                |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>关键规则</strong>：</p><ul><li>画面描述要<strong>视觉化</strong>，不要抽象（&quot;悲伤的氛围&quot;→&quot;灰蓝色调，雨滴沿窗玻璃下滑&quot;）</li><li>每个镜头标注<strong>运镜方式</strong>（固定/推轨/横移/跟拍）</li><li>对白控制在<strong>每镜1-2句</strong>，AI 配音有字数限制</li></ul><hr><h2 id="第二站-分镜阶段" tabindex="-1">第二站：分镜阶段 <a class="header-anchor" href="#第二站-分镜阶段" aria-label="Permalink to &quot;第二站：分镜阶段&quot;">​</a></h2><h3 id="从剧本到提示词" tabindex="-1">从剧本到提示词 <a class="header-anchor" href="#从剧本到提示词" aria-label="Permalink to &quot;从剧本到提示词&quot;">​</a></h3><p>这是工作流最关键的环节。剧本里的&quot;赛博朋克街道夜景&quot;需要翻译成 AI 能精确理解的提示词。</p><p><strong>分镜提示词五层结构：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes custom-dark custom-dark vp-code" tabindex="0"><code><span class="line"><span>[主体描述] → [环境场景] → [光线设定] → [技术摄影] → [风格美学]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>示例——把剧本一行的&quot;画面描述&quot;展开为完整提示词：</strong></p><blockquote><p>主体：东京赛博朋克街道，霓虹灯招牌密集悬挂，约15-20块不同大小的全息广告牌 环境：雨后的湿沥青路面，倒映霓虹灯光，路面积水形成镜面反射。远景有悬浮飞行器尾灯轨迹 光线：多光源——霓虹招牌以品红(#ff00ff)和青色(#00ffff)为主，路灯钠灯橙色(#ff8800)，地面反射光为混合色 技术：广角24mm，低角度仰拍，大景深全焦，HDR高动态范围 风格：赛博朋克2077风格，PBR写实渲染，HDR高动态范围</p></blockquote><h3 id="风格帧" tabindex="-1">风格帧 <a class="header-anchor" href="#风格帧" aria-label="Permalink to &quot;风格帧&quot;">​</a></h3><p>在批量生产前，先花 20 分钟做一个<strong>风格帧</strong>——用一段完整的提示词生成一张概念图，确认整体视觉方向。</p><p><strong>风格帧检查清单</strong>：</p><ul><li>[ ] 色调是否符合内容调性（温馨=暖色、悬疑=冷色、科技=蓝紫）</li><li>[ ] 角色设计是否贯穿一致（服饰、发型、体型）</li><li>[ ] 光线方案是否可行（避免过于复杂的光源组合）</li><li>[ ] 整体质感是否达标（写实度、细节密度）</li></ul><p>风格帧通过后再进入批量生成。这是<strong>花 20 分钟省 2 小时</strong>的投资。</p><hr><h2 id="第三站-生成阶段" tabindex="-1">第三站：生成阶段 <a class="header-anchor" href="#第三站-生成阶段" aria-label="Permalink to &quot;第三站：生成阶段&quot;">​</a></h2><h3 id="工具矩阵" tabindex="-1">工具矩阵 <a class="header-anchor" href="#工具矩阵" aria-label="Permalink to &quot;工具矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>最佳场景</th><th style="text-align:center;">分辨率</th><th style="text-align:center;">速度</th><th style="text-align:center;">成本</th></tr></thead><tbody><tr><td><strong>Seedance 2.0</strong></td><td>真人风格短剧、需要首尾帧控制</td><td style="text-align:center;">1080p</td><td style="text-align:center;">中</td><td style="text-align:center;">中</td></tr><tr><td><strong>可灵 (Kling)</strong></td><td>创意特效、超现实场景</td><td style="text-align:center;">1080p</td><td style="text-align:center;">快</td><td style="text-align:center;">低</td></tr><tr><td><strong>即梦 (Jimeng)</strong></td><td>动漫/二次元、轻量快速</td><td style="text-align:center;">720p-1080p</td><td style="text-align:center;">极快</td><td style="text-align:center;">极低</td></tr><tr><td><strong>Runway Gen-4</strong></td><td>电影级画质、精细控制</td><td style="text-align:center;">4K</td><td style="text-align:center;">慢</td><td style="text-align:center;">高</td></tr><tr><td><strong>Pika 2.0</strong></td><td>社交媒体短视频、趣味效果</td><td style="text-align:center;">1080p</td><td style="text-align:center;">快</td><td style="text-align:center;">低</td></tr></tbody></table><h3 id="批量生成策略" tabindex="-1">批量生成策略 <a class="header-anchor" href="#批量生成策略" aria-label="Permalink to &quot;批量生成策略&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes custom-dark custom-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#888890;--shiki-dark-font-style:italic;--shiki-light:#888890;--shiki-light-font-style:italic;">#</span><span style="--shiki-dark:#555560;--shiki-dark-font-style:italic;--shiki-light:#555560;--shiki-light-font-style:italic;"> 批量生成脚本框架</span></span>
<span class="line"><span style="--shiki-dark:#888890;--shiki-dark-font-style:italic;--shiki-light:#888890;--shiki-light-font-style:italic;">#</span><span style="--shiki-dark:#555560;--shiki-dark-font-style:italic;--shiki-light:#555560;--shiki-light-font-style:italic;"> 输入：分镜CSV（镜头编号, 提示词, 时长, 运镜方式）</span></span>
<span class="line"><span style="--shiki-dark:#888890;--shiki-dark-font-style:italic;--shiki-light:#888890;--shiki-light-font-style:italic;">#</span><span style="--shiki-dark:#555560;--shiki-dark-font-style:italic;--shiki-light:#555560;--shiki-light-font-style:italic;"> 输出：对应视频片段</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#C084FC;--shiki-dark-font-weight:bold;--shiki-light:#C084FC;--shiki-light-font-weight:bold;">for</span><span style="--shiki-dark:#CCCCCC;--shiki-light:#CCCCCC;"> each 镜头 in 分镜表:</span></span>
<span class="line"><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;">    1.</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 用主提示词生成</span><span style="--shiki-dark:#FBBF24;--shiki-light:#FBBF24;"> 3</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 个候选版本（同提示词×3）</span></span>
<span class="line"><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;">    2.</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 快速筛选：去模糊、去变形、去不自然的运动</span></span>
<span class="line"><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;">    3.</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 最佳版本</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> →</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 入库，标记镜头编号</span></span>
<span class="line"><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;">    4.</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 如果3版都不满意</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> →</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 调整提示词</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> →</span><span style="--shiki-dark:#38BDF8;--shiki-light:#38BDF8;"> 再生成2版</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><blockquote><p><strong>质量铁律</strong>：每个镜头至少生成 3 个候选。AI 视频的随机性意味着第一版就满意的概率不到 30%。</p></blockquote><h3 id="角色一致性控制" tabindex="-1">角色一致性控制 <a class="header-anchor" href="#角色一致性控制" aria-label="Permalink to &quot;角色一致性控制&quot;">​</a></h3><p>AI 视频最大的痛点是<strong>换镜头就换脸</strong>。解决方案：</p><table tabindex="0"><thead><tr><th>方法</th><th style="text-align:center;">效果</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>参考图锁定</strong>：每个角色1张正面+1张侧面参考图</td><td style="text-align:center;">⭐⭐⭐⭐</td><td>Seedance 2.0</td></tr><tr><td><strong>详细文字描述</strong>：面部特征写到毛孔级（见提示词工程篇）</td><td style="text-align:center;">⭐⭐⭐</td><td>所有工具</td></tr><tr><td><strong>LoRA 微调</strong>：训练角色模型</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td><td>长剧集、系列内容</td></tr><tr><td><strong>后期修复</strong>：同一角色多镜头取最佳帧→手动替换</td><td style="text-align:center;">⭐⭐</td><td>短内容应急</td></tr></tbody></table><hr><h2 id="第四站-后期阶段" tabindex="-1">第四站：后期阶段 <a class="header-anchor" href="#第四站-后期阶段" aria-label="Permalink to &quot;第四站：后期阶段&quot;">​</a></h2><h3 id="剪辑拼接" tabindex="-1">剪辑拼接 <a class="header-anchor" href="#剪辑拼接" aria-label="Permalink to &quot;剪辑拼接&quot;">​</a></h3><p>AI 生成的素材通常有这些问题：</p><ul><li>片段间转场生硬</li><li>部分帧出现形变</li><li>画面抖动</li></ul><p><strong>剪辑流程：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes custom-dark custom-dark vp-code" tabindex="0"><code><span class="line"><span>1. 粗剪：按剧本时间线排列所有片段</span></span>
<span class="line"><span>2. 去瑕疵：逐片段检查形变帧 → 裁剪或替换</span></span>
<span class="line"><span>3. 转场：添加交叉溶解（0.3-0.5秒）或硬切</span></span>
<span class="line"><span>4. 稳定：对抖动片段用剪映/AE的稳定功能</span></span>
<span class="line"><span>5. 调色：统一所有片段的白平衡和曝光</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>工具推荐</strong>：剪映专业版（免费、AI 功能丰富）、DaVinci Resolve（专业调色）。</p><h3 id="ai-配音" tabindex="-1">AI 配音 <a class="header-anchor" href="#ai-配音" aria-label="Permalink to &quot;AI 配音&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th style="text-align:center;">音色数量</th><th style="text-align:center;">中文质量</th><th style="text-align:center;">情感控制</th></tr></thead><tbody><tr><td><strong>剪映</strong></td><td style="text-align:center;">100+</td><td style="text-align:center;">⭐⭐⭐⭐</td><td style="text-align:center;">基础</td></tr><tr><td><strong>微软 Azure TTS</strong></td><td style="text-align:center;">300+</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td><td style="text-align:center;">支持SSML标签调节</td></tr><tr><td><strong>ElevenLabs</strong></td><td style="text-align:center;">1000+</td><td style="text-align:center;">⭐⭐⭐</td><td style="text-align:center;">精细情感参数</td></tr><tr><td><strong>Fish Audio</strong></td><td style="text-align:center;">开源</td><td style="text-align:center;">⭐⭐⭐</td><td style="text-align:center;">可微调</td></tr></tbody></table><p><strong>配音规范</strong>：</p><ul><li>语速：中文 3-4 字/秒（短视频可稍快）</li><li>停顿：句号 0.5s，段落 1s</li><li>音色一致性：同一角色全片用同一音色</li></ul><hr><h2 id="第五站-发布与数据闭环" tabindex="-1">第五站：发布与数据闭环 <a class="header-anchor" href="#第五站-发布与数据闭环" aria-label="Permalink to &quot;第五站：发布与数据闭环&quot;">​</a></h2><h3 id="多平台适配" tabindex="-1">多平台适配 <a class="header-anchor" href="#多平台适配" aria-label="Permalink to &quot;多平台适配&quot;">​</a></h3><table tabindex="0"><thead><tr><th>平台</th><th style="text-align:center;">时长</th><th style="text-align:center;">比例</th><th>封面要点</th></tr></thead><tbody><tr><td>抖音</td><td style="text-align:center;">15-60s</td><td style="text-align:center;">9:16</td><td>大字标题+人物表情特写</td></tr><tr><td>B站</td><td style="text-align:center;">3-15min</td><td style="text-align:center;">16:9</td><td>信息密度高的标题卡片</td></tr><tr><td>小红书</td><td style="text-align:center;">15-90s</td><td style="text-align:center;">3:4</td><td>高饱和度画面+治愈系文字</td></tr><tr><td>视频号</td><td style="text-align:center;">30-120s</td><td style="text-align:center;">9:16</td><td>正能量+情感共鸣标题</td></tr></tbody></table><h3 id="发布时间窗口" tabindex="-1">发布时间窗口 <a class="header-anchor" href="#发布时间窗口" aria-label="Permalink to &quot;发布时间窗口&quot;">​</a></h3><p>基于 2026 年最新的平台流量数据：</p><ul><li><strong>抖音</strong>：工作日 12:00-13:00 / 18:00-20:00，周末 10:00-12:00</li><li><strong>B站</strong>：工作日 12:00-14:00 / 18:00-22:00</li><li><strong>小红书</strong>：工作日 7:30-8:30 / 12:00-13:00 / 20:00-22:00</li><li><strong>视频号</strong>：工作日 6:30-8:00 / 20:00-22:00</li></ul><h3 id="数据复盘模板" tabindex="-1">数据复盘模板 <a class="header-anchor" href="#数据复盘模板" aria-label="Permalink to &quot;数据复盘模板&quot;">​</a></h3><p>每发布 5 条视频后复盘一次：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes custom-dark custom-dark vp-code" tabindex="0"><code><span class="line"><span>1. 完播率：&gt;30% 合格，&gt;50% 优秀</span></span>
<span class="line"><span>2. 互动率（点赞+评论+收藏）：&gt;3% 合格，&gt;8% 爆发</span></span>
<span class="line"><span>3. 粉丝转化：每条带来多少新关注</span></span>
<span class="line"><span>4. 问题诊断：</span></span>
<span class="line"><span>   - 前3秒跳出率高 → 开头不够抓人</span></span>
<span class="line"><span>   - 中途跳出 → 节奏有问题</span></span>
<span class="line"><span>   - 互动低 → 缺少&quot;钩子&quot;引导互动</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="工具链总览" tabindex="-1">工具链总览 <a class="header-anchor" href="#工具链总览" aria-label="Permalink to &quot;工具链总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>工具</th><th style="text-align:center;">费用</th></tr></thead><tbody><tr><td>剧本</td><td>Claude / DeepSeek</td><td style="text-align:center;">免费-¥20/月</td></tr><tr><td>分镜提示词</td><td>Claude（结构化提示词生成）</td><td style="text-align:center;">同上</td></tr><tr><td>图像生成</td><td>gpt-image-2 / Midjourney / 即梦</td><td style="text-align:center;">¥100-500/月</td></tr><tr><td>视频生成</td><td>Seedance / 可灵 / 即梦</td><td style="text-align:center;">¥200-1000/月</td></tr><tr><td>配音</td><td>剪映（免费）/ Azure TTS</td><td style="text-align:center;">¥0-100/月</td></tr><tr><td>剪辑</td><td>剪映专业版</td><td style="text-align:center;">免费</td></tr><tr><td>BGM</td><td>剪映内置 / Epidemic Sound</td><td style="text-align:center;">¥0-100/月</td></tr><tr><td>发布</td><td>各平台创作中心</td><td style="text-align:center;">免费</td></tr></tbody></table><blockquote><p><strong>月总预算</strong>：最低 ¥300，推荐 ¥1000-2000。对比传统拍摄团队（月成本 3-10 万），AI 工作流的成本是传统方式的 3-10%。</p></blockquote><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>📖 阅读<a href="/ai-creator-guide/posts/prompt-engineering.html">提示词工程深度指南</a>——精确控制 AI 输出的系统方法论</li><li>🎬 用本工作流制作你的第一条 AI 短剧</li><li>📊 记录每个环节的实际耗时和成本，找到瓶颈优化</li></ul><hr><p><em>上一篇：<a href="/ai-creator-guide/posts/agent-skills-guide.html">Agent Skills 完全指南</a></em><em>下一篇：<a href="/ai-creator-guide/posts/claude-code-guide.html">Claude Code 深度实战指南</a></em></p>`,78)])])}const g=s(l,[["render",i]]);export{b as __pageData,g as default};
